data.content:
Here's the pattern for testing async code with cancellation and timeouts in MSTest:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Stub handler to control HttpClient responses
    private sealed class StubHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(Delay, cancellationToken);   // honors the token
            return Response;
        }
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new StubHandler
        {
            Response = new(HttpStatusCode.OK) { Content = new StringContent("hello") }
        };
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new StubHandler
        {
            Response = new(HttpStatusCode.InternalServerError)
        };
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new StubHandler { Delay = TimeSpan.FromSeconds(30) };
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();

        cts.Cancel();   // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]   // safety net — fail the test if it hangs
    public async Task FetchAsync_Throws_WhenTokenCancelledDuringRequest()
    {
        var handler = new StubHandler { Delay = TimeSpan.FromSeconds(30) };
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key takeaways:**

- **Stub the handler, not HttpClient** — `HttpMessageHandler.SendAsync` is the seam; pass the token through to `Task.Delay` so cancellation works realistically.
- **Pre-cancelled token** — `cts.Cancel()` before calling verifies the fast path.
- **Timed cancellation** — `new CancellationTokenSource(TimeSpan)` simulates a timeout mid-request.
- **`[Timeout(5000)]`** — MSTest's safety net so a broken test fails fast instead of hanging your CI. Apply it to any test involving real delays.
- **Avoid `Task.Delay` in assertions** — let the `CancellationToken` drive timing; never `Thread.Sleep` in async tests.
